import{_ as s,o as a,c as e,a6 as t}from"./chunks/framework.DtxWasON.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"mainchain/software/und_cmd/und_start.md","filePath":"mainchain/software/und_cmd/und_start.md"}'),p={name:"mainchain/software/und_cmd/und_start.md"};function i(o,n,l,r,c,d){return a(),e("div",null,[...n[0]||(n[0]=[t(`<h2 id="und-start" tabindex="-1">und start <a class="header-anchor" href="#und-start" aria-label="Permalink to &quot;und start&quot;">​</a></h2><p>Run the full node</p><h3 id="synopsis" tabindex="-1">Synopsis <a class="header-anchor" href="#synopsis" aria-label="Permalink to &quot;Synopsis&quot;">​</a></h3><p>Run the full node application with CometBFT in or out of process. By default, the application will run with CometBFT in process.</p><p>Pruning options can be provided via the &#39;--pruning&#39; flag or alternatively with &#39;--pruning-keep-recent&#39;, and &#39;pruning-interval&#39; together.</p><p>For &#39;--pruning&#39; the options are as follows:</p><p>default: the last 362880 states are kept, pruning at 10 block intervals nothing: all historic states will be saved, nothing will be deleted (i.e. archiving node) everything: 2 latest states will be kept; pruning at 10 block intervals. custom: allow pruning options to be manually specified through &#39;pruning-keep-recent&#39;, and &#39;pruning-interval&#39;</p><p>Node halting configurations exist in the form of two flags: &#39;--halt-height&#39; and &#39;--halt-time&#39;. During the ABCI Commit phase, the node will check if the current block height is greater than or equal to the halt-height or if the current block time is greater than or equal to the halt-time. If so, the node will attempt to gracefully shutdown and the block will not be committed. In addition, the node will not be able to commit subsequent blocks.</p><p>For profiling and benchmarking purposes, CPU profiling can be enabled via the &#39;--cpu-profile&#39; flag which accepts a path for the resulting pprof file.</p><p>The node may be started in a &#39;query only&#39; mode where only the gRPC and JSON HTTP API services are enabled via the &#39;grpc-only&#39; flag. In this mode, CometBFT is bypassed and can be used when legacy queries are needed after an on-chain upgrade is performed. Note, when enabled, gRPC will also be automatically enabled.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>und start [flags]</span></span></code></pre></div><h3 id="options" tabindex="-1">Options <a class="header-anchor" href="#options" aria-label="Permalink to &quot;Options&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>      --abci string                                     specify abci transport (socket | grpc) (default &quot;socket&quot;)</span></span>
<span class="line"><span>      --address string                                  Listen address (default &quot;tcp://127.0.0.1:26658&quot;)</span></span>
<span class="line"><span>      --api.address string                              the API server address to listen on (default &quot;tcp://localhost:1317&quot;)</span></span>
<span class="line"><span>      --api.enable                                      Define if the API server should be enabled</span></span>
<span class="line"><span>      --api.enabled-unsafe-cors                         Define if CORS should be enabled (unsafe - use it at your own risk)</span></span>
<span class="line"><span>      --api.max-open-connections uint                   Define the number of maximum open connections (default 1000)</span></span>
<span class="line"><span>      --api.rpc-max-body-bytes uint                     Define the CometBFT maximum request body (in bytes) (default 1000000)</span></span>
<span class="line"><span>      --api.rpc-read-timeout uint                       Define the CometBFT RPC read timeout (in seconds) (default 10)</span></span>
<span class="line"><span>      --api.rpc-write-timeout uint                      Define the CometBFT RPC write timeout (in seconds)</span></span>
<span class="line"><span>      --api.swagger                                     Define if swagger documentation should automatically be registered (Note: the API must also be enabled)</span></span>
<span class="line"><span>      --consensus.create_empty_blocks                   set this to false to only produce blocks when there are txs or when the AppHash changes (default true)</span></span>
<span class="line"><span>      --consensus.create_empty_blocks_interval string   the possible interval between empty blocks (default &quot;0s&quot;)</span></span>
<span class="line"><span>      --consensus.double_sign_check_height int          how many blocks to look back to check existence of the node&#39;s consensus votes before joining consensus</span></span>
<span class="line"><span>      --cpu-profile string                              Enable CPU profiling and write to the provided file</span></span>
<span class="line"><span>      --db_backend string                               database backend: goleveldb | cleveldb | boltdb | rocksdb | badgerdb (default &quot;goleveldb&quot;)</span></span>
<span class="line"><span>      --db_dir string                                   database directory (default &quot;data&quot;)</span></span>
<span class="line"><span>      --genesis_hash bytesHex                           optional SHA-256 hash of the genesis file</span></span>
<span class="line"><span>      --grpc-only                                       Start the node in gRPC query only mode (no CometBFT process is started)</span></span>
<span class="line"><span>      --grpc-web.enable                                 Define if the gRPC-Web server should be enabled. (Note: gRPC must also be enabled) (default true)</span></span>
<span class="line"><span>      --grpc.address string                             the gRPC server address to listen on (default &quot;localhost:9090&quot;)</span></span>
<span class="line"><span>      --grpc.enable                                     Define if the gRPC server should be enabled (default true)</span></span>
<span class="line"><span>      --halt-height uint                                Block height at which to gracefully halt the chain and shutdown the node</span></span>
<span class="line"><span>      --halt-time uint                                  Minimum block time (in Unix seconds) at which to gracefully halt the chain and shutdown the node</span></span>
<span class="line"><span>  -h, --help                                            help for start</span></span>
<span class="line"><span>      --home string                                     The application home directory (default &quot;/home/hodge/.und_mainchain&quot;)</span></span>
<span class="line"><span>      --iavl-disable-fastnode                           Disable fast node for IAVL tree</span></span>
<span class="line"><span>      --inter-block-cache                               Enable inter-block caching (default true)</span></span>
<span class="line"><span>      --inv-check-period uint                           Assert registered invariants every N blocks</span></span>
<span class="line"><span>      --mempool.max-txs int                             Sets MaxTx value for the app-side mempool (default -1)</span></span>
<span class="line"><span>      --min-retain-blocks uint                          Minimum block height offset during ABCI commit to prune CometBFT blocks</span></span>
<span class="line"><span>      --minimum-gas-prices string                       Minimum gas prices to accept for transactions; Any fee in a tx must meet this minimum (e.g. 0.01photino;0.0001stake)</span></span>
<span class="line"><span>      --moniker string                                  node name (default &quot;hodge-MS-7A59&quot;)</span></span>
<span class="line"><span>      --p2p.external-address string                     ip:port address to advertise to peers for them to dial</span></span>
<span class="line"><span>      --p2p.laddr string                                node listen address. (0.0.0.0:0 means any interface, any port) (default &quot;tcp://0.0.0.0:26656&quot;)</span></span>
<span class="line"><span>      --p2p.persistent_peers string                     comma-delimited ID@host:port persistent peers</span></span>
<span class="line"><span>      --p2p.pex                                         enable/disable Peer-Exchange (default true)</span></span>
<span class="line"><span>      --p2p.private_peer_ids string                     comma-delimited private peer IDs</span></span>
<span class="line"><span>      --p2p.seed_mode                                   enable/disable seed mode</span></span>
<span class="line"><span>      --p2p.seeds string                                comma-delimited ID@host:port seed nodes</span></span>
<span class="line"><span>      --p2p.unconditional_peer_ids string               comma-delimited IDs of unconditional peers</span></span>
<span class="line"><span>      --priv_validator_laddr string                     socket address to listen on for connections from external priv_validator process</span></span>
<span class="line"><span>      --proxy_app string                                proxy app address, or one of: &#39;kvstore&#39;, &#39;persistent_kvstore&#39; or &#39;noop&#39; for local testing. (default &quot;tcp://127.0.0.1:26658&quot;)</span></span>
<span class="line"><span>      --pruning string                                  Pruning strategy (default|nothing|everything|custom) (default &quot;default&quot;)</span></span>
<span class="line"><span>      --pruning-interval uint                           Height interval at which pruned heights are removed from disk (ignored if pruning is not &#39;custom&#39;)</span></span>
<span class="line"><span>      --pruning-keep-recent uint                        Number of recent heights to keep on disk (ignored if pruning is not &#39;custom&#39;)</span></span>
<span class="line"><span>      --query-gas-limit uint                            Maximum gas a Rest/Grpc query can consume. Blank and 0 imply unbounded.</span></span>
<span class="line"><span>      --rpc.grpc_laddr string                           GRPC listen address (BroadcastTx only). Port required</span></span>
<span class="line"><span>      --rpc.laddr string                                RPC listen address. Port required (default &quot;tcp://127.0.0.1:26657&quot;)</span></span>
<span class="line"><span>      --rpc.pprof_laddr string                          pprof listen address (https://golang.org/pkg/net/http/pprof)</span></span>
<span class="line"><span>      --rpc.unsafe                                      enabled unsafe rpc methods</span></span>
<span class="line"><span>      --shutdown-grace duration                         On Shutdown, duration to wait for resource clean up</span></span>
<span class="line"><span>      --state-sync.snapshot-interval uint               State sync snapshot interval</span></span>
<span class="line"><span>      --state-sync.snapshot-keep-recent uint32          State sync snapshot to keep (default 2)</span></span>
<span class="line"><span>      --trace                                           Provide full stack traces for errors in ABCI Log</span></span>
<span class="line"><span>      --trace-store string                              Enable KVStore tracing to an output file</span></span>
<span class="line"><span>      --transport string                                Transport protocol: socket, grpc (default &quot;socket&quot;)</span></span>
<span class="line"><span>      --unsafe-skip-upgrades ints                       Skip a set of upgrade heights to continue the old binary</span></span>
<span class="line"><span>      --with-comet                                      Run abci app embedded in-process with CometBFT (default true)</span></span>
<span class="line"><span>      --x-crisis-skip-assert-invariants                 Skip x/crisis invariants check on startup</span></span></code></pre></div><h3 id="see-also" tabindex="-1">SEE ALSO <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;SEE ALSO&quot;">​</a></h3><ul><li><a href="./und.html">und</a> - Unification Mainchain App</li></ul><h6 id="auto-generated-by-spf13-cobra-on-6-may-2025" tabindex="-1">Auto generated by spf13/cobra on 6-May-2025 <a class="header-anchor" href="#auto-generated-by-spf13-cobra-on-6-may-2025" aria-label="Permalink to &quot;Auto generated by spf13/cobra on 6-May-2025&quot;">​</a></h6>`,16)])])}const g=s(p,[["render",i]]);export{h as __pageData,g as default};
